const input = $input.first().json;

const p1 = input['Profilname 1 (Pflicht)'] || '';
const p2 = input['Profilname 2 (optional)'] || '';
const p3 = input['Profilname 3 (optional)'] || '';

const profiles = [p1, p2, p3].filter(function(p) { return p.trim() !== ''; });

function detectPlatform(s) {
  const lower = s.toLowerCase();
  if (lower.indexOf('instagram.com') !== -1 || lower.indexOf('instagr.am') !== -1) return 'instagram';
  if (lower.indexOf('facebook.com') !== -1 || lower.indexOf('fb.com') !== -1) return 'facebook';
  if (lower.indexOf('youtube.com') !== -1 || lower.indexOf('youtu.be') !== -1) return 'youtube';
  if (lower.indexOf('linkedin.com') !== -1) return 'linkedin';
  if (lower.indexOf('tiktok.com') !== -1) return 'tiktok';
  if (lower.indexOf('twitter.com') !== -1 || lower.indexOf('x.com') !== -1) return 'x_twitter';
  return 'unknown';
}

function extractHandle(s) {
  const trimmed = s.trim();
  const match = trimmed.match(/\/([^\/\?#]+)\/?$/);
  if (match) return match[1].replace(/^@/, '');
  return trimmed.replace(/^@/, '');
}

const detected = [];
for (let i = 0; i < profiles.length; i++) {
  detected.push({ input: profiles[i], platform: detectPlatform(profiles[i]), handle: extractHandle(profiles[i]) });
}

return [{ json: { detected: detected, rawProfiles: profiles } }];

