const claudeResponse = $input.first().json.content;
let profiles;
try {
  const contentArr = claudeResponse;
  const text = Array.isArray(contentArr) ? contentArr[0].text : ((claudeResponse && claudeResponse.text) ? claudeResponse.text : String(claudeResponse || ''));
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  profiles = JSON.parse(cleaned);
} catch(e) {
  const detected = $('Plattform erkennen').first().json.detected;
  profiles = [];
  for (let i = 0; i < detected.length; i++) {
    const d = detected[i];
    profiles.push({
      input: d.input,
      platform: d.platform,
      handle: d.handle,
      accounts: {
        instagram: { handle: d.handle, url: 'https://instagram.com/' + d.handle, confidence: 'low' },
        facebook: { handle: d.handle, url: 'https://facebook.com/' + d.handle, confidence: 'low' },
        youtube: { handle: d.handle, url: 'https://youtube.com/@' + d.handle, confidence: 'low' },
        linkedin: { handle: d.handle, url: 'https://linkedin.com/company/' + d.handle, confidence: 'low' },
        tiktok: { handle: d.handle, url: 'https://tiktok.com/@' + d.handle, confidence: 'low' }
      }
    });
  }
}

const competitors = [];
const activePlatforms = ['instagram', 'facebook', 'youtube', 'linkedin', 'tiktok'];

for (let pi = 0; pi < profiles.length; pi++) {
  const profile = profiles[pi];
  const accountEntries = Object.keys(profile.accounts || {});
  for (let ai = 0; ai < accountEntries.length; ai++) {
    const plat = accountEntries[ai];
    const acct = profile.accounts[plat];
    if (activePlatforms.indexOf(plat) === -1) continue;
    const name = profile.handle || profile.input;
    competitors.push({
      'Name': name + ' (' + plat + ')',
      'Plattform': plat,
      'Account-URL': acct.url,
      'Account-ID': acct.handle,
      '_confidence': acct.confidence,
      '_sourceProfile': profile.input,
      '_detectedPlatform': profile.platform
    });
  }
}

const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const dayOfYear = Math.floor((now - startOfYear) / 86400000);
const calendarWeek = Math.ceil((dayOfYear + startOfYear.getDay() + 1) / 7);

return [{
  json: {
    competitors: competitors,
    activePlatforms: activePlatforms,
    calendarWeek: calendarWeek,
    year: now.getFullYear(),
    projectName: 'Manuell per Profilname',
    brandName: 'Eigene Marke',
    brandDescription: 'Per Formular gestartete Wettbewerbsanalyse',
    branche: 'Allgemein',
    config: { skipClaude: false, maxPostsPerCompetitor: 20 },
    timestamp: now.toISOString(),
    profiles: profiles
  }
}];

const input = $input.first().json;
const config = input.config;
const competitors = input.competitors;
const activePlatforms = input.activePlatforms;
const calendarWeek = input.calendarWeek;
const year = input.year;
const projectName = input.projectName;
const brandName = input.brandName;
const brandDescription = input.brandDescription;
const branche = input.branche;
const timestamp = input.timestamp;

const staticData = $getWorkflowStaticData('global');
staticData.results = [];
staticData.errors = [];
staticData.analyses = [];
staticData.startedAt = new Date().toISOString();

const items = [];

for (let i = 0; i < competitors.length; i++) {
  const comp = competitors[i];
  const platform = (comp['Plattform'] || '').toLowerCase();
  const name = comp['Name'] || '';
  const url = comp['Account-URL'] || '';
  const accountId = comp['Account-ID'] || '';

  if (activePlatforms.indexOf(platform) === -1) continue;
  if (!name || !url) {
    staticData.errors.push({ competitor: name || 'unbekannt', platform: platform, error: 'Name oder Account-URL fehlt', timestamp: new Date().toISOString() });
    continue;
  }

  items.push({
    json: { competitorName: name, platform: platform, accountUrl: url, accountId: accountId, calendarWeek: calendarWeek, year: year, projectName: projectName, brandName: brandName, brandDescription: brandDescription, branche: branche, config: config, timestamp: timestamp, _confidence: comp['_confidence'] || 'medium' }
  });
}

if (items.length === 0) {
  return [{ json: { _empty: true, _skip: true, message: 'Keine aktiven Wettbewerber gefunden', calendarWeek: calendarWeek, year: year, projectName: projectName, timestamp: timestamp } }];
}

return items;

// URL-Validierung pro Plattform
// Prueft ob das Profil unter der generierten URL erreichbar ist.
// Gibt Output 0 (valid) oder Output 1 (invalid) zurueck via _urlValid flag.

const item = $input.first().json;
const platform = item.platform || '';
const accountUrl = item.accountUrl || '';
const handle = item.accountId || '';
const confidence = item._confidence || 'medium';

// Bei high confidence und direkter URL-Eingabe ueberspringen wir die Validierung
if (confidence === 'high') {
  return [{ json: Object.assign({}, item, { _urlValid: true, _validationSkipped: true, _validationReason: 'confidence=high, URL direkt eingegeben' }) }];
}

// LinkedIn blockiert HTTP-Requests zuverlaessig, daher Handle-Format-Pruefung
if (platform === 'linkedin') {
  const isValidHandle = handle && /^[a-zA-Z0-9\-\.]+$/.test(handle) && handle.length >= 2 && handle.length <= 100;
  if (!isValidHandle) {
    return [{ json: Object.assign({}, item, { _urlValid: false, _validationReason: 'LinkedIn Handle hat ungueltiges Format: ' + handle }) }];
  }
  return [{ json: Object.assign({}, item, { _urlValid: true, _validationSkipped: true, _validationReason: 'LinkedIn: Handle-Format gueltig, HTTP-Pruefung nicht moeglich' }) }];
}

// Fuer IG/FB/TT/YT: HTTP-Request zur Profilseite
try {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 8000);

  let finalUrl = accountUrl;
  if (platform === 'youtube' && handle && !accountUrl.includes('@')) {
    finalUrl = 'https://www.youtube.com/@' + handle;
  }
  if (platform === 'tiktok' && handle && !accountUrl.includes('@')) {
    finalUrl = 'https://www.tiktok.com/@' + handle;
  }
  if (platform === 'instagram') {
    finalUrl = 'https://www.instagram.com/' + handle + '/';
  }
  if (platform === 'facebook') {
    finalUrl = 'https://www.facebook.com/' + handle;
  }

  const response = await fetch(finalUrl, {
    method: 'GET',
    signal: controller.signal,
    redirect: 'follow',
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
      'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      'Accept-Language': 'de-DE,de;q=0.9,en-US;q=0.8,en;q=0.7'
    }
  });
  clearTimeout(timeout);

  const status = response.status;
  const redirectedUrl = response.url;

  let isValid = false;
  let reason = '';

  if (status === 404) {
    isValid = false;
    reason = 'HTTP 404 - Profil nicht gefunden: ' + finalUrl;
  } else if (status === 200) {
    const redirectedToLogin = redirectedUrl && (
      redirectedUrl.includes('/login') ||
      redirectedUrl.includes('/signin') ||
      redirectedUrl.includes('/accounts/login') ||
      redirectedUrl.includes('challenge') ||
      redirectedUrl.includes('checkpoint')
    );
    if (redirectedToLogin) {
      isValid = true;
      reason = 'HTTP 200 (Login-Redirect, Profil existiert wahrscheinlich)';
    } else {
      isValid = true;
      reason = 'HTTP 200 - Profil gefunden';
    }
  } else if (status >= 400 && status !== 429) {
    isValid = false;
    reason = 'HTTP ' + status + ' - Profil vermutlich nicht vorhanden';
  } else {
    isValid = true;
    reason = 'HTTP ' + status + ' - unklar, als gueltig angenommen';
  }

  return [{ json: Object.assign({}, item, {
    _urlValid: isValid,
    _validationStatus: status,
    _validationUrl: finalUrl,
    _validationReason: reason
  }) }];

} catch(err) {
  const isTimeout = err.name === 'AbortError';
  return [{ json: Object.assign({}, item, {
    _urlValid: true,
    _validationSkipped: true,
    _validationReason: isTimeout ? 'Timeout (8s) - als gueltig angenommen' : 'Fehler: ' + err.message + ' - als gueltig angenommen'
  }) }];
}

const staticData = $getWorkflowStaticData('global');
const platformInfo = $('Plattform Switch').first().json;
const competitorName = platformInfo.competitorName;
