  const followers = posts[0].ownerFollowerCount || posts[0].followersCount || 0;
  const sorted = posts.slice().sort(function(a, b) { return ((b.likesCount||b.likes||0)+(b.commentsCount||b.comments||0)) - ((a.likesCount||a.likes||0)+(a.commentsCount||a.comments||0)); });
  const top3 = sorted.slice(0, 3).map(function(p) { return { url: p.url || (p.shortCode ? 'https://instagram.com/p/' + p.shortCode : ''), text: (p.caption || '').substring(0, 500), likes: p.likesCount||p.likes||0, comments: p.commentsCount||p.comments||0, shares: 0, engagement: (p.likesCount||p.likes||0)+(p.commentsCount||p.comments||0), date: p.timestamp||p.takenAtTimestamp||'', type: p.videoViewCount ? 'video' : p.carouselMediaCount ? 'carousel' : 'image' }; });
