  const avgLikes = posts.length > 0 ? totalLikes/posts.length : 0;
  const avgComments = posts.length > 0 ? totalComments/posts.length : 0;
  const engagementRate = followers > 0 ? ((avgLikes+avgComments)/followers*100) : 0;
  return [{ json: { competitorName: competitorName, platform: platform, accountUrl: accountUrl, followers: followers, postsScraped: posts.length, avgLikes: Math.round(avgLikes*100)/100, avgComments: Math.round(avgComments*100)/100, avgShares: 0, engagementRate: Math.round(engagementRate*10000)/10000, topPosts: top3, topComments: topComments.slice(0,20), calendarWeek: calendarWeek, year: year, projectName: projectName, status: 'ok' } }];
